import java.sql.*;

public class SQLInjectionSecureCode {
    public static void main(String[] args) {
        try {
            String userInput = "'; DROP TABLE users; --"; // This is the user input that contains malicious SQL code

            // Connect to the database
            Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Create a prepared statement with a parameter
            String sql = "SELECT * FROM users WHERE username = ?";
            PreparedStatement statement = connection.prepareStatement(sql);
            statement.setString(1, userInput); // Set the parameter value

            // Execute the query using the prepared statement
            ResultSet resultSet = statement.executeQuery();

            while (resultSet.next()) {
                System.out.println(resultSet.getString("username"));
            }

            connection.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
